ax[1,1].hist(eq_global.ravel(), 256, [0,256]);    ax[1,1].set_title('After global: spread')
ax[1,2].imshow(cv2.cvtColor(colour_eq, cv2.COLOR_BGR2RGB)); ax[1,2].set_title('Colour V-equalized')
