            title: 'Detect autocorrelation, heteroscedasticity, and a structural break',
            code: `import numpy as np, pandas as pd
import matplotlib.pyplot as plt
from statsmodels.tsa.stattools import acf
from statsmodels.stats.diagnostic import het_arch

np.random.seed(1)
n = 300; y = np.zeros(n)
for i in range(1,n):
    y[i] = 0.8*y[i-1] + np.random.normal(0, 1+0.02*i)   # AR(1) + growing var
y[200:] += 5                                            # structural break

s = pd.Series(y)
print("ACF[1:4]:", np.round(acf(s, nlags=3)[1:],3))
print("ARCH p-value:", round(het_arch(s)[1], 4))        # <0.05 -> heteroscedastic

roll = s.rolling(30).mean()
plt.figure(figsize=(10,4))
plt.plot(s, color="grey", alpha=0.5, label="raw")
plt.plot(roll, color="crimson", label="30-step rolling mean")
plt.title("Rolling mean reveals the structural break at t=200")
plt.xlabel("t"); plt.legend(); plt.grid(alpha=0.3); plt.tight_layout(); plt.show()`,
            output: 'ACF[1:4] ~ [0.78, 0.62, 0.50]; ARCH p-value < 0.001; rolling mean jumps after t=200.',
