            title: 'Compare all four baselines on AirPassengers',
            code: `import pandas as pd, numpy as np
import matplotlib.pyplot as plt
from sklearn.metrics import mean_absolute_percentage_error as mape

url="https://raw.githubusercontent.com/jbrownlee/Datasets/master/airline-passengers.csv"
df=pd.read_csv(url); df['Month']=pd.to_datetime(df['Month'])
y=df.set_index('Month')['Passengers'].asfreq('MS')
cut=int(len(y)*0.8); train,test=y.iloc[:cut],y.iloc[cut:]; h=len(test)

naive  = pd.Series(np.repeat(train.iloc[-1],h), index=test.index)
avg    = pd.Series(np.repeat(train.mean(),h),    index=test.index)
drift  = pd.Series(train.iloc[-1]+np.arange(1,h+1)*(train.iloc[-1]-train.iloc[0])/(len(train)-1), index=test.index)
snaive = pd.Series(np.tile(train.iloc[-12:].values, h//12+1)[:h], index=test.index)

for name,fc in [("naive",naive),("average",avg),("drift",drift),("seasonal-naive",snaive)]:
    print(f"{name:14s} MAPE={mape(test,fc)*100:5.2f}%")

plt.figure(figsize=(11,5))
plt.plot(train.index,train,label="train")
plt.plot(test.index,test,label="actual",color="black")
plt.plot(test.index,snaive,label="seasonal-naive",color="crimson")
plt.plot(test.index,drift,label="drift",color="navy")
plt.title("Simple baselines on AirPassengers"); plt.legend(); plt.xlabel("Month"); plt.ylabel("Passengers")
plt.grid(alpha=0.3); plt.tight_layout(); plt.show()`,
