            code: `import pandas as pd, numpy as np
from sklearn.metrics import mean_absolute_error, mean_squared_error, mean_absolute_percentage_error
from statsmodels.tsa.holtwinters import ExponentialSmoothing
from statsmodels.tsa.arima.model import ARIMA

idx = pd.date_range("2017-01-01", periods=72, freq="MS")
np.random.seed(4)
y = pd.Series(100 + 0.5*np.arange(72) + 12*np.sin(2*np.pi*np.arange(72)/12)
              + np.random.normal(0,4,72), index=idx)

def mase(y_true, y_pred, naive_mae):
    return np.mean(np.abs(y_true-y_pred))/naive_mae

h=6; folds=[]
for o in range(48, len(y)-h+1, 6):           # rolling origin
    tr, te = y.iloc[:o], y.iloc[o:o+h]
    nm = np.mean(np.abs(np.diff(tr)))
    hw  = ExponentialSmoothing(tr, trend="add", seasonal="add", seasonal_periods=12).fit().forecast(h)
    ar  = ARIMA(tr, order=(1,1,1)).fit().forecast(h)
    folds.append(("HW", mean_absolute_error(te,hw), np.sqrt(mean_squared_error(te,hw)),
                  mean_absolute_percentage_error(te,hw)*100, mase(te,hw,nm)))
    folds.append(("AR", mean_absolute_error(te,ar), np.sqrt(mean_squared_error(te,ar)),
                  mean_absolute_percentage_error(te,ar)*100, mase(te,ar,nm)))

import pandas as pd
df = pd.DataFrame(folds, columns=["model","MAE","RMSE","MAPE","MASE"])
print(df.groupby("model").mean().round(2))`,
