plot_pacf(ar_series, lags=20, ax=ax[0,1], method="ywm"); ax[0,1].set_title("AR(1) PACF (cuts at 1)")
plot_acf(ma_series, lags=20, ax=ax[1,0]); ax[1,0].set_title("MA(1) ACF (cuts at 1)")
