            code: `import numpy as np, pandas as pd
import matplotlib.pyplot as plt
from statsmodels.tsa.api import VAR
from statsmodels.tsa.stattools import adfuller

# generate 3 interacting stationary series
np.random.seed(0); n=300
y = np.zeros((n,3))
for i in range(1,n):
    y[i,0] = 0.5*y[i-1,0] + 0.2*y[i-1,1] + np.random.normal(0,1)
    y[i,1] = 0.1*y[i-1,0] + 0.4*y[i-1,1] + np.random.normal(0,1)
    y[i,2] = 0.3*y[i-1,2] + 0.1*y[i-1,0] + np.random.normal(0,1)
df = pd.DataFrame(y, columns=["gdp","infl","rate"],
                  index=pd.date_range("2000-01-01", periods=n, freq="M"))

print("ADF p per series:", [round(adfuller(df[c])[1],3) for c in df.columns])  # all <0.05

model = VAR(df)
res = model.fit(maxlags=5, ic="aic")
print("selected order:", res.k_ar)
print("AIC:", round(res.aic,2))
fc = res.forecast(df.values[-res.k_ar:], 6)
print("6-step forecast:\\n", pd.DataFrame(fc, columns=df.columns).round(3))

res.irf(periods=12).plot(); plt.tight_layout(); plt.show()`,
