            code: `import numpy as np, pandas as pd
from statsmodels.tsa.api import VAR
from statsmodels.tsa.statespace.varmax import VARMAX
from statsmodels.stats.diagnostic import acorr_ljungbox

np.random.seed(5); n=300; y=np.zeros((n,2))
e = np.random.normal(size=(n,2))
for i in range(1,n):
    # VARMA(1,1)-style DGP: AR + MA on shocks
    y[i] = 0.5*y[i-1,0:2]*0 + (np.array([[0.5,0.1],[0.1,0.4]]) @ y[i-1])            + e[i] + np.array([[0.3,0],[0,0.3]]) @ e[i-1]
df=pd.DataFrame(y, columns=["A","B"])

var_fit   = VAR(df).fit(1)
varma_fit = VARMAX(df, order=(1,1)).fit(disp=False)

for name, resid in [("VAR(1)", var_fit.resid), ("VARMA(1,1)", varma_fit.resid)]:
    p = acorr_ljungbox(resid[:,0], lags=[8], return_df=True)["lb_pvalue"].iloc[0]
    print(name, "Ljung-Box p (series A):", round(p,3))`,
