            code: `import numpy as np, pandas as pd
from statsmodels.tsa.api import VAR
from statsmodels.tsa.stattools import coint

np.random.seed(6); n=300
# two cointegrated random walks: y2 follows y1 + spread
e1=np.random.normal(0,1,n); e2=np.random.normal(0,1,n)
y1=np.cumsum(e1); y2=y1 + np.cumsum(e2*0.3) + 2
df=pd.DataFrame({"y1":y1,"y2":y2})

# 1) VAR in differences (stationary) and check stability
stat=df.diff().dropna()
res=VAR(stat).fit(2)
print("VAR stable (eig<1):", res.is_stable(verbose=False))

# 2) Granger causality on differences
print(res.test_causality("y1",["y2"], kind="f").pvalue.round(4))

# 3) Cointegration on the levels (Engle-Granger)
coint_res=coint(df["y1"], df["y2"])
print("Engle-Granger p-value:", round(coint_res[1],4), "(<0.05 -> cointegrated)")`,
